window.SmartRisk=window.SmartRisk||{};(function(){const SR=SmartRisk;let institutions=SR.Storage.get("institutions",SR.MockData.institutions),filtered=[...institutions],selectedId=institutions[0]?.id||"";function persist(){SR.Storage.set("institutions",institutions)}function summary(){return `<section class="institution-summary"><article class="institution-summary-card"><span>Instituciones</span><strong>${filtered.length}</strong><small class="muted">Registros visibles</small></article><article class="institution-summary-card"><span>Operativas</span><strong>${filtered.filter(x=>x.estado==="Operativa").length}</strong><small class="muted">Con capacidad activa</small></article><article class="institution-summary-card"><span>Mesas / grupos</span><strong>${new Set(filtered.map(x=>x.mtt)).size}</strong><small class="muted">Espacios de coordinación</small></article><article class="institution-summary-card"><span>Provincias</span><strong>${new Set(filtered.map(x=>x.provincia)).size}</strong><small class="muted">Cobertura institucional</small></article></section>`}function detail(){const x=institutions.find(i=>i.id===selectedId);if(!x)return '<div class="empty-state">Seleccione una institución.</div>';return `<div class="institution-detail"><div><span class="kicker">${x.sigla}</span><h2 class="page-title" style="font-size:1.55rem">${x.nombre}</h2><p class="muted">${x.tipo} · ${x.provincia}</p></div><div class="detail-row"><span>Estado</span><span class="badge ${x.estado==="Operativa"?"badge-success":"badge-warning"}">${x.estado}</span></div><div class="detail-row"><span>Mesa / grupo</span><strong>${x.mtt}</strong></div><div class="contact-card"><strong>${x.responsable}</strong><span>${x.cargo}</span><span>${x.telefono}</span><span>${x.correo}</span></div><div><strong>Competencias</strong><div class="tag-list" style="margin-top:10px">${x.competencias.map(c=>`<span class="tag">${c}</span>`).join("")}</div></div><div><strong>Observaciones</strong><p class="muted" style="margin-top:8px">${x.observaciones||"Sin observaciones."}</p></div><div class="split-actions"><button id="edit-selected" class="btn btn-secondary">${SR.Icon.render("edit",17)}Editar</button><button id="delete-selected" class="btn btn-secondary">${SR.Icon.render("trash",17)}Eliminar</button></div></div>`}function render(){return `<section class="page-header"><div><span class="kicker">Directorio institucional</span><h1 class="page-title">Instituciones</h1><p class="page-subtitle">Gestiona actores, responsables, competencias y espacios de coordinación.</p></div><div class="split-actions">${SR.Button.render({id:"export-institutions",label:"Exportar CSV",variant:"secondary",icon:"download"})}${SR.Button.render({id:"new-institution",label:"Nueva institución",icon:"plus"})}</div></section><div id="institution-summary-root">${summary()}</div><section class="panel" style="margin-bottom:20px"><div class="panel-body"><div class="institution-filter-grid"><div class="search-wrap"><span class="search-icon">${SR.Icon.render("search",18)}</span><input id="institution-search" class="search-input" placeholder="Buscar institución, sigla o responsable…"></div><select id="institution-type" class="select-input"><option value="">Todos los tipos</option>${[...new Set(institutions.map(x=>x.tipo))].map(x=>`<option>${x}</option>`).join("")}</select><select id="institution-status" class="select-input"><option value="">Todos los estados</option><option>Operativa</option><option>En coordinación</option></select><button id="institution-reset" class="btn btn-secondary">Limpiar</button></div></div></section><section class="institution-layout"><article class="panel"><header class="panel-header"><h2 class="section-title">Directorio</h2><span class="badge" id="institution-count">${filtered.length} registros</span></header><div class="panel-body"><div id="institution-table"></div></div></article>${SR.Card.panel({title:"Detalle institucional",body:`<div id="institution-detail-root">${detail()}</div>`})}</section>`}function drawTable(){SR.Table.create({containerId:"institution-table",columns:[{key:"sigla",label:"Sigla"},{key:"nombre",label:"Institución"},{key:"tipo",label:"Tipo"},{key:"provincia",label:"Provincia"},{key:"mtt",label:"Mesa"},{key:"estado",label:"Estado",type:"status"},{key:"id",label:"Detalle",type:"action"}],rows:filtered,onAction:id=>{selectedId=id;document.getElementById("institution-detail-root").innerHTML=detail();bindDetail()}});document.getElementById("institution-count").textContent=`${filtered.length} registros`}function applyFilters(){const q=SR.Utils.normalizeText(document.getElementById("institution-search").value),t=document.getElementById("institution-type").value,s=document.getElementById("institution-status").value;filtered=institutions.filter(x=>SR.Utils.normalizeText(`${x.nombre} ${x.sigla} ${x.responsable}`).includes(q)&&(!t||x.tipo===t)&&(!s||x.estado===s));document.getElementById("institution-summary-root").innerHTML=summary();drawTable()}function form(x={}){return `<div class="form-grid"><label class="form-field"><span class="form-label">Nombre *</span><input id="f-nombre" class="form-input" value="${SR.Utils.escapeHtml(x.nombre||"")}"></label><label class="form-field"><span class="form-label">Sigla *</span><input id="f-sigla" class="form-input" value="${SR.Utils.escapeHtml(x.sigla||"")}"></label><label class="form-field"><span class="form-label">Tipo</span><input id="f-tipo" class="form-input" value="${SR.Utils.escapeHtml(x.tipo||"")}"></label><label class="form-field"><span class="form-label">Provincia</span><input id="f-provincia" class="form-input" value="${SR.Utils.escapeHtml(x.provincia||"")}"></label><label class="form-field"><span class="form-label">Estado</span><select id="f-estado" class="select-input"><option ${x.estado==="Operativa"?"selected":""}>Operativa</option><option ${x.estado==="En coordinación"?"selected":""}>En coordinación</option></select></label><label class="form-field"><span class="form-label">Mesa / grupo</span><input id="f-mtt" class="form-input" value="${SR.Utils.escapeHtml(x.mtt||"")}"></label><label class="form-field"><span class="form-label">Responsable</span><input id="f-responsable" class="form-input" value="${SR.Utils.escapeHtml(x.responsable||"")}"></label><label class="form-field"><span class="form-label">Cargo</span><input id="f-cargo" class="form-input" value="${SR.Utils.escapeHtml(x.cargo||"")}"></label><label class="form-field"><span class="form-label">Teléfono</span><input id="f-telefono" class="form-input" value="${SR.Utils.escapeHtml(x.telefono||"")}"></label><label class="form-field"><span class="form-label">Correo</span><input id="f-correo" class="form-input" value="${SR.Utils.escapeHtml(x.correo||"")}"></label><label class="form-field form-field-full"><span class="form-label">Competencias (separadas por coma)</span><input id="f-competencias" class="form-input" value="${SR.Utils.escapeHtml((x.competencias||[]).join(", "))}"></label><label class="form-field form-field-full"><span class="form-label">Observaciones</span><textarea id="f-observaciones" class="form-textarea">${SR.Utils.escapeHtml(x.observaciones||"")}</textarea></label></div>`}function readForm(existing={}){const get=id=>document.getElementById(id).value.trim(),nombre=get("f-nombre"),sigla=get("f-sigla");if(!nombre||!sigla){SR.Toast.show("Nombre y sigla son obligatorios.","danger");return null}return {...existing,id:existing.id||SR.Utils.uid("INS"),nombre,sigla,tipo:get("f-tipo")||"Sin clasificar",provincia:get("f-provincia")||"Zonal",estado:get("f-estado"),mtt:get("f-mtt")||"Sin asignar",responsable:get("f-responsable")||"Sin responsable",cargo:get("f-cargo"),telefono:get("f-telefono"),correo:get("f-correo"),competencias:get("f-competencias").split(",").map(x=>x.trim()).filter(Boolean),observaciones:get("f-observaciones")}}function openForm(existing=null){SR.Modal.open({title:existing?"Editar institución":"Nueva institución",body:form(existing||{}),confirmLabel:existing?"Guardar cambios":"Crear institución",onConfirm:()=>{const value=readForm(existing||{});if(!value)return false;if(existing)institutions=institutions.map(x=>x.id===existing.id?value:x);else institutions=[value,...institutions];filtered=[...institutions];selectedId=value.id;persist();SR.Toast.show(existing?"Institución actualizada.":"Institución creada.","success");location.hash="/instituciones";setTimeout(()=>SR.Router.start?.(),0)}})}function bindDetail(){document.getElementById("edit-selected")?.addEventListener("click",()=>openForm(institutions.find(x=>x.id===selectedId)));document.getElementById("delete-selected")?.addEventListener("click",()=>{const x=institutions.find(i=>i.id===selectedId);SR.Modal.open({title:"Eliminar institución",body:`<p>¿Confirma la eliminación de <strong>${x.nombre}</strong>?</p>`,confirmLabel:"Eliminar",onConfirm:()=>{institutions=institutions.filter(i=>i.id!==selectedId);filtered=[...institutions];selectedId=institutions[0]?.id||"";persist();SR.Toast.show("Institución eliminada.","success");location.reload()}})})}function bind(){drawTable();bindDetail();document.getElementById("institution-search").oninput=applyFilters;document.getElementById("institution-type").onchange=applyFilters;document.getElementById("institution-status").onchange=applyFilters;document.getElementById("institution-reset").onclick=()=>{document.getElementById("institution-search").value="";document.getElementById("institution-type").value="";document.getElementById("institution-status").value="";applyFilters()};document.getElementById("new-institution").onclick=()=>openForm();document.getElementById("export-institutions").onclick=()=>{SR.Utils.downloadCsv("instituciones-smartrisk.csv",filtered.map(x=>({...x,competencias:x.competencias.join("; ")})));SR.Toast.show("CSV generado.","success")}}SR.InstitucionesModule={route:{path:"/instituciones",title:"Instituciones",render,bind}}})();